def visual_checks(topic: str) -> List[str]:
    return [
        f"The main {topic} labels stay fully visible on desktop and mobile layouts.",
        "Motion arrows, component arrows, and inward-force arrows remain separated so the direction story never collapses into one line bundle.",
        "Axis, radius, and field-strength labels stay readable without clipping into the probe path or the beacon body.",
        "Equation or value badges remain outside the main path geometry so calculation cues do not hide the physical picture.",
    ]


def probe_field_map(focus: str) -> Dict[str, Any]:
    return {
        "model_name": "Probe-Field Model",
        "focus": focus,
        "comparison": f"The Probe-Field world keeps constant acceleration, projectiles, circular motion, and gravitational fields inside one motion-arrow story while {focus}.",
        "mapping": [
            "Mission probe -> moving object or particle",
            "Run span -> displacement",
            "Start pace -> initial velocity",
            "End pace -> final velocity",
            "Steady shift -> acceleration",
            "Clock count -> time",
            "Steady-Push Lane -> constant-acceleration region",
            "Launch split -> horizontal and vertical components",
            "Drop field -> gravitational acceleration near Earth",
            "Orbit Ring -> circular path",
            "Center pull -> centripetal force",
            "Turn rate -> centripetal acceleration",
            "Mass beacon -> source mass",
            "Pull map -> gravitational field",
        ],
        "limit": "The model keeps motion arrows, inward turning, and radial gravity coherent, but learners still need the formal vector, component, centripetal, and inverse-square language.",
        "prediction_prompt": f"Use the Probe-Field model to predict what should happen when {focus}.",
    }


def sim_contract(asset_id: str, concept: str, focus_prompt: str, baseline_case: str, comparison_tasks: Sequence[str], watch_for: str, takeaway: str, controls: Sequence[Tuple[str, str, str]], readouts: Sequence[Tuple[str, str]]) -> Dict[str, Any]:
    return {
        "asset_id": asset_id,
        "concept": concept,
        "focus_prompt": focus_prompt,
        "baseline_case": baseline_case,
        "comparison_tasks": list(comparison_tasks),
        "watch_for": watch_for,
        "takeaway": takeaway,
        "controls": [{"variable": variable, "label": label, "why_it_matters": why_it_matters} for variable, label, why_it_matters in controls],
        "readouts": [{"label": label, "meaning": meaning} for label, meaning in readouts],
    }


def contract(*, concept_targets: Sequence[str], core_concepts: Sequence[str], prerequisite_lessons: Sequence[str], misconception_focus: Sequence[str], formulas: Sequence[Dict[str, Any]], representations: Sequence[Dict[str, Any]], analogy_map: Dict[str, Any], worked_examples: Sequence[Dict[str, Any]], visual_assets: Sequence[Dict[str, Any]], animation_assets: Sequence[Dict[str, Any]], simulation_contract: Dict[str, Any], reflection_prompts: Sequence[str], mastery_skills: Sequence[str], variation_plan: Dict[str, str], scaffold_support: Dict[str, Any], visual_clarity_checks: Sequence[str]) -> Dict[str, Any]:
    return {
        "concept_targets": list(concept_targets),
        "core_concepts": list(core_concepts),
        "prerequisite_lessons": list(prerequisite_lessons),
        "misconception_focus": safe_tags(misconception_focus),
        "formulas": [deepcopy(item) for item in formulas],
        "representations": [deepcopy(item) for item in representations],
        "analogy_map": deepcopy(analogy_map),
        "worked_examples": [deepcopy(item) for item in worked_examples],
        "visual_assets": [deepcopy(item) for item in visual_assets],
        "animation_assets": [deepcopy(item) for item in animation_assets],
        "simulation_contract": deepcopy(simulation_contract),
        "reflection_prompts": list(reflection_prompts),
        "mastery_skills": list(mastery_skills),
        "variation_plan": deepcopy(variation_plan),
        "assessment_bank_targets": assessment_targets(),
        "scaffold_support": deepcopy(scaffold_support),
        "visual_clarity_checks": list(visual_clarity_checks),
    }


def sim(lab_id: str, title: str, description: str, instructions: Sequence[str], outcomes: Sequence[str], fields: Sequence[str], depth: str) -> Dict[str, Any]:
    return {"lab_id": lab_id, "title": title, "description": description, "instructions": list(instructions), "outcomes": list(outcomes), "fields": list(fields), "depth": depth}


def lesson_spec(lesson_id: str, title: str, sim_meta: Dict[str, Any], diagnostic: Sequence[Dict[str, Any]], analogy_text: str, commitment_prompt: str, micro_prompts: Sequence[Dict[str, str]], inquiry: Sequence[Dict[str, str]], recon_prompts: Sequence[str], capsule_prompt: str, capsule_checks: Sequence[Dict[str, Any]], transfer: Sequence[Dict[str, Any]], contract_payload: Dict[str, Any]) -> Dict[str, Any]:
    return {
        "id": lesson_id,
        "title": title,
        "sim": deepcopy(sim_meta),
        "diagnostic": list(diagnostic),
        "analogy_text": analogy_text,
        "commitment_prompt": commitment_prompt,
        "micro_prompts": list(micro_prompts),
        "inquiry": list(inquiry),
        "recon_prompts": list(recon_prompts),
        "capsule_prompt": capsule_prompt,
        "capsule_checks": list(capsule_checks),
        "transfer": list(transfer),
        "contract": deepcopy(contract_payload),
    }


