        mcq("A1L3_M2", "Using the previous projectile, the horizontal displacement to the top is...", ["19.2 m", "12 m", "25.6 m", "32 m"], 0, "Use x = ux x t.", ["time_link_projectile_confusion"], skill_tags=["horizontal_motion", "time_link_projectile"]),
        mcq("A1L3_M3", "A projectile is launched horizontally at 14 m/s and lands after 3 s. The horizontal range is...", ["42 m", "17 m", "9 m", "56 m"], 0, "Horizontal motion is uniform.", ["horizontal_acceleration_confusion"], skill_tags=["horizontal_motion"]),
        mcq("A1L3_M4", "A projectile is launched with uy = 18 m/s upward. Taking g = 9 m/s^2, the vertical velocity after 1 s is...", ["9 m/s upward", "27 m/s upward", "-9 m/s downward", "18 m/s upward"], 0, "uy decreases by g each second.", ["projectile_component_coupling"], skill_tags=["vertical_motion"]),
