        mcq("A1L3_M6", "A projectile has u = 20 m/s at 30 degrees. Using sin 30 = 0.5, uy is...", ["10 m/s", "17.3 m/s", "40 m/s", "0.5 m/s"], 0, "Vertical component uses sine.", ["projectile_component_coupling"], skill_tags=["resolve_components"]),
