        mcq("A1L3_M10", "Best summary of Lesson 3:", ["Projectile motion is two component motions linked by time.", "Projectile motion needs one special curve formula only.", "Acceleration vanishes at the top.", "Horizontal motion accelerates downward."], 0, "That is the core lesson summary.", ["projectile_component_coupling"], skill_tags=["resolve_components"]),
