    return lesson_spec("A1_L3", "Split the Launch", sim("a1_launch_split_lab", "Launch split lab", "Launch the probe into the sky and compare horizontal and vertical motion as separate component stories tied by time.", ["Set launch speed and angle.", "Read ux and uy separately.", "Track the probe to the top and to landing."], ["Resolve launch velocity into components.", "Explain why horizontal and vertical motions are independent.", "Connect top-of-flight reasoning to the unchanged drop field."], ["launch_speed", "launch_angle", "ux", "uy", "time", "range"], "Projectile-component reasoning."), diagnostic, "In the Launch Sky the probe begins with one arrow, but that arrow is split into a forward part and a vertical part. After launch the drop field acts only downward, so the horizontal story and the vertical story can be solved separately and then reconnected through time.", "Do not solve the curve as one mysterious law. Split the motion arrow first.", [prompt_block("What stays unchanged horizontally after launch in the simple model?", "Horizontal velocity stays constant because horizontal acceleration is zero."), prompt_block("What still acts at the top of the flight?", "The downward drop field, so ay stays -g.")], [prompt_block("Increase the launch angle with the same speed.", "The horizontal and vertical components should rebalance."), prompt_block("Freeze the projectile at the top.", "The vertical velocity can be zero there even though the downward acceleration remains.")], ["Why does a projectile need components even though the visible path is one curve?", "Why does the top of the flight not remove the downward acceleration?"], "Use the Launch Sky to rebuild projectile motion as two one-dimensional stories sharing one clock.", concept, mastery, contract(concept_targets=["Resolve a launch velocity into horizontal and vertical components.", "Analyse projectile motion as independent component motions linked by time.", "Explain why acceleration stays downward at the top of the flight."], core_concepts=["Projectile motion splits into horizontal and vertical components.", "With negligible air resistance, horizontal acceleration is zero.", "Vertical acceleration remains -g throughout the flight near Earth.", "The horizontal and vertical solutions are linked by common time."], prerequisite_lessons=["A1_L1", "F1_L2"], misconception_focus=["projectile_component_coupling", "projectile_top_acceleration_zero", "horizontal_acceleration_confusion", "time_link_projectile_confusion"], formulas=[relation("u_x = u cos(theta)", "Resolve the launch speed into its horizontal component.", ["m/s"], "Use when the angle is measured from the horizontal."), relation("u_y = u sin(theta)", "Resolve the launch speed into its vertical component.", ["m/s"], "Use when the angle is measured from the horizontal."), relation("a_x = 0, a_y = -g", "Near Earth the projectile has no horizontal acceleration and a constant downward acceleration.", ["m/s^2"], "Use in the simple no-air-resistance model.")], representations=[representation("words", "Explains component independence and common time."), representation("formula", "Shows the component and acceleration relations."), representation("diagram", "Displays the split motion arrow and the curved path."), representation("model", "Uses the Launch Sky and drop field as the central picture.")], analogy_map=probe_field_map("the learner splits the launch arrow before solving the curved flight"), worked_examples=[worked("A projectile has ux = 12 m/s for 3 s. Find horizontal displacement.", ["Use the horizontal story only.", "x = ux x t.", "Substitute 12 x 3."], "36 m", "Zero horizontal acceleration means the horizontal speed stays constant.", "This anchors the independent horizontal motion."), worked("A projectile has uy = 20 m/s upward, with g = 10 m/s^2. Find time to the top.", ["At the top the vertical velocity becomes zero.", "Use 0 = 20 - 10t.", "Solve for t."], "2 s", "The vertical component changes uniformly under gravity.", "This shows how the top-of-flight condition works."), worked("A learner says acceleration is zero at the top because the projectile 'stops'. Diagnose the issue.", ["Separate vertical velocity from acceleration.", "Notice that only vy becomes zero briefly.", "Keep ay = -g throughout."], "The statement is incorrect", "Zero velocity and zero acceleration are different claims.", "This is the key misconception shield for the lesson.")], visual_assets=[visual("a1_l3_launch_split_diagram", "launch_split", "Launch split separates the forward and vertical stories", "Show the initial motion arrow resolved into ux and uy, the curved path, and the constant downward field.", "Solve the curve by components: horizontal uniform motion plus vertical gravity-driven motion.")], animation_assets=[animation("a1_l3_launch_split_animation", "launch_split", "Projectile component motion", "Animate the projectile path while keeping the horizontal and vertical component arrows visible.")], simulation_contract=sim_contract("a1_l3_launch_split_sim", "launch_split", "Compare launch angle, launch speed, and time so the component story stays visible all the way through the flight.", "Start with a medium launch speed and a 45-degree launch in the simple no-air-resistance model.", ["Change the launch angle while keeping speed fixed and compare ux and uy.", "Pause the motion at the top and compare vertical velocity with vertical acceleration."], "Watch for the unchanged horizontal velocity, the constant downward acceleration, and the way time links both component calculations.", "Projectile motion becomes much easier once the launch arrow is split and each component is solved in its own direction.", controls=[("launch_speed", "Launch speed", "Sets the size of the initial motion arrow."), ("launch_angle", "Launch angle", "Rebalances the horizontal and vertical components."), ("gravity", "Drop field", "Controls the vertical acceleration."), ("time", "Time marker", "Links the horizontal and vertical readouts.")], readouts=[("u_x", "Shows the horizontal launch component."), ("u_y", "Shows the vertical launch component."), ("Range so far", "Tracks the horizontal displacement at the chosen time.")]), reflection_prompts=["Explain how the same projectile can be one curved path and two separate component calculations at the same time.", "Describe what is true about velocity and acceleration at the top of the flight."], mastery_skills=["resolve_components", "horizontal_motion", "vertical_motion", "top_of_flight", "time_link_projectile"], variation_plan={"diagnostic": "Fresh attempts rotate between component definitions, top-of-flight statements, and simple one-direction calculations with new numbers.", "concept_gate": "Concept-gate retries alternate between component explanations, time-link reasoning, and short calculations for range or time to top.", "mastery": "Mastery varies lesson-owned launch-angle, component, and top-of-flight prompts so fresh attempts prefer new stems and new values."}, scaffold_support=scaffold("Split the launch arrow before you touch the equations.", "The curved path is the combined result of one uniform horizontal story and one gravity-driven vertical story.", "What stays the same horizontally, and what keeps changing vertically?", "Treating the visible curve as if it needs one special mystery formula.", "The mission probe carries one arrow into the Launch Sky. Splitting that arrow reveals two simpler stories running on the same clock.", "Why does the common time let you reconnect the horizontal and vertical parts?", extras=[extra_section("Component habit", "Resolve ux and uy as soon as the launch angle appears so the later equations stay one-dimensional.", "Which component uses cosine?"), extra_section("Top-of-flight shield", "At the top the vertical velocity can be zero, but the drop field has not turned off.", "What is still equal to -g at the top?")]), visual_clarity_checks=visual_checks("launch-split")))


